class ElasticsearchQueryBuilder {
  /**
   * Build a filter clause from a validated filter object
   */
  static buildFilterClause(filter) {
    const { field, operator, value } = filter;

    switch (operator) {
      case 'eq':
        return { term: { [`${field}.keyword`]: value } };
      case 'neq':
        return { bool: { must_not: [{ term: { [`${field}.keyword`]: value } }] } };
      case 'gt':
        return { range: { [field]: { gt: value } } };
      case 'gte':
        return { range: { [field]: { gte: value } } };
      case 'lt':
        return { range: { [field]: { lt: value } } };
      case 'lte':
        return { range: { [field]: { lte: value } } };
      case 'in':
        return { terms: { [`${field}.keyword`]: value } };
      case 'range':
        return {
          range: {
            [field]: {
              ...(value.from !== undefined && { gte: value.from }),
              ...(value.to !== undefined && { lte: value.to }),
            },
          },
        };
      case 'exists':
        return { exists: { field } };
      default:
        throw new Error(`Unsupported operator: ${operator}`);
    }
  }

  /**
   * Build aggregations from validated aggregation configs
   */
  static buildAggregations(aggregations) {
    if (!aggregations || aggregations.length === 0) return undefined;

    const aggs = {};
    for (const agg of aggregations) {
      switch (agg.type) {
        case 'terms':
          aggs[agg.name] = {
            terms: {
              field: `${agg.field}.keyword`,
              size: agg.size,
            },
          };
          break;
        case 'date_histogram':
          aggs[agg.name] = {
            date_histogram: {
              field: agg.field,
              calendar_interval: 'month',
            },
          };
          break;
        case 'stats':
          aggs[agg.name] = {
            stats: {
              field: agg.field,
            },
          };
          break;
        default:
          break;
      }
    }
    return Object.keys(aggs).length > 0 ? aggs : undefined;
  }

  /**
   * Build the complete Elasticsearch query from validated parameters
   */
  static buildQuery(params) {
    const { query, fields, filters, scoring, pagination, sort, highlight, aggregations } = params;

    // Build base multi_match query
    const baseQuery = {
      multi_match: {
        query: query,
        fields: fields,
        type: 'best_fields',
        fuzziness: 'AUTO',
        prefix_length: 2,
        max_expansions: 50,
      },
    };

    // Build filter clauses
    const filterClauses = filters.map(f => this.buildFilterClause(f));

    // Construct the bool query
    let boolQuery = {
      bool: {
        must: [baseQuery],
        ...(filterClauses.length > 0 && { filter: filterClauses }),
      },
    };

    // Apply scoring strategy if provided
    let finalQuery;
    if (scoring) {
      const strategy = SCORING_STRATEGIES[scoring.strategy];
      if (!strategy) {
        throw new Error(`Unknown scoring strategy: ${scoring.strategy}`);
      }

      const scoringConfig = strategy.buildScript(scoring.params);
      scoringConfig.script_score.query = boolQuery;
      finalQuery = scoringConfig;
    } else {
      finalQuery = boolQuery;
    }

    // Build the complete search body
    const searchBody = {
      query: finalQuery,
      from: (pagination.page - 1) * pagination.size,
      size: pagination.size,
      track_total_hits: true,
    };

    // Add sorting
    if (sort && sort.length > 0) {
      searchBody.sort = sort.map(s => {
        if (s.field === '_score') {
          return { _score: { order: s.order } };
        }
        return { [s.field]: { order: s.order, missing: '_last' } };
      });
    }

    // Add highlighting
    if (highlight) {
      const highlightFields = {};
      for (const field of fields) {
        const fieldName = field.split('^')[0];
        highlightFields[fieldName] = {
          fragment_size: 150,
          number_of_fragments: 3,
          pre_tags: ['<mark>'],
          post_tags: ['</mark>'],
        };
      }
      searchBody.highlight = {
        fields: highlightFields,
        encoder: 'html',
      };
    }

    // Add aggregations
    const aggs = this.buildAggregations(aggregations);
    if (aggs) {
      searchBody.aggs = aggs;
    }

    return searchBody;
  }
}

