// Main search endpoint
app.post('/api/search', async (req, res) => {
  try {
    // Validate request body against schema
    const { error, value: validatedParams } = searchRequestSchema.validate(req.body, {
      abortEarly: false,
      stripUnknown: true,
    });

    if (error) {
      const details = error.details.map(d => ({
        field: d.path.join('.'),
        message: d.message,
      }));
      logger.warn('Search validation failed', { details });
      return res.status(400).json({
        error: 'Validation failed',
        details,
      });
    }

    // Build the Elasticsearch query from validated parameters
    const searchBody = ElasticsearchQueryBuilder.buildQuery(validatedParams);

    // Log the search request (without sensitive data)
    logger.info('Search request', {
      index: validatedParams.index,
      queryLength: validatedParams.query.length,
      fieldsCount: validatedParams.fields.length,
      filtersCount: validatedParams.filters.length,
      scoringStrategy: validatedParams.scoring?.strategy || 'none',
      page: validatedParams.pagination.page,
      size: validatedParams.pagination.size,
    });

    // Execute the search
    const result = await esClient.search({
      index: validatedParams.index,
      body: searchBody,
    });

    // Format response
    const response = {
      meta: {
        total: typeof result.hits.total === 'object' ? result.hits.total.value : result.hits.total,
        page: validatedParams.pagination.page,
        size: validatedParams.pagination.size,
        took: result.took,
        scoring_strategy: validatedParams.scoring?.strategy || 'default',
      },
      hits: result.hits.hits.map(hit => ({
        id: hit._id,
        index: hit._index,
        score: hit._score,
        source: hit._source,
        highlight: hit.highlight || {},
      })),
    };

    // Include aggregations if present
    if (result.aggregations) {
      response.aggregations = {};
      for (const [name, agg] of Object.entries(result.aggregations)) {
        if (agg.buckets) {
          response.aggregations[name] = agg.buckets.map(bucket => ({
            key: bucket.key_as_string || bucket.key,
            count: bucket.doc_count,
          }));
        } else {
          response.aggregations[name] = agg;
        }
      }
    }

    res.json(response);
  } catch (err) {
    // Don't leak internal error details to the client
    logger.error('Search execution failed', {
      error: err.message,
      statusCode: err.statusCode,
    });

    if (err.statusCode === 404) {
      return res.status(404).json({ error: 'Index not found' });
    }

    res.status(500).json({ error: 'Search execution failed. Please try again later.' });
  }
});

