app.post('/api/suggest', async (req, res) => {
  const suggestSchema = Joi.object({
    index: Joi.string()
      .required()
      .custom((value, helpers) => {
        if (!ALLOWED_INDICES.has(value)) {
          return helpers.error('any.invalid');
        }
        return value;
      }),
    query: Joi.string().required().min(1).max(100).trim(),
    field: Joi.string()
      .default('title')
      .custom((value, helpers) => {
        if (!ALLOWED_SEARCH_FIELDS.has(value)) {
          return helpers.error('any.invalid');
        }
        return value;
      }),
    size: Joi.number().integer().min(1).max(20).default(5),
  });

  try {
    const { error, value: params } = suggestSchema.validate(req.body, {
      abortEarly: false,
      stripUnknown: true,
    });

    if (error) {
      return res.status(400).json({
        error: 'Validation failed',
        details: error.details.map(d => ({
          field: d.path.join('.'),
          message: d.message,
        })),
      });
    }

    const result = await esClient.search({
      index: params.index,
      body: {
        size: params.size,
        _source: [params.field],
        query: {
          match_phrase_prefix: {
            [params.field]: {
              query: params.query,
              max_expansions: 10,
            },
          },
        },
      },
    });

    res.json({
      suggestions: result.hits.hits.map(hit => ({
        id: hit._id,
        text: hit._source[params.field],
        score: hit._score,
      })),
    });
  } catch (err) {
    logger.error('Suggest execution failed', { error: err.message });
    res.status(500).json({ error: 'Suggestion request failed.' });
  }
});

